class Solution {
public:
    int countCharacters(vector<string>& words, string chars) {
        unordered_map<char, int> charCount;
        for (char c : chars) {
            charCount[c]++;
        }
        int sum = 0;
        for (string word : words) {
            bool isGood = true;
            unordered_map<char, int> wordCount;
            for (char c : word) {
                if (charCount[c] == 0 || wordCount[c]++ >= charCount[c]) {
                    isGood = false;
                    break;
                }
            }
            if (isGood) {
                sum += word.length();
            }
        }
        return sum;
    }
};
```
